//! Integration tests for G-code analysis covering all Phase 21 success criteria (SC1-SC7).
//!
//! Tests use synthetic G-code generated in memory (no external files required)
//! for CI-safe execution. Real G-code tests are gated with `#[ignore]`.

/// Generate a minimal BambuStudio-style G-code with:
/// - Header block with HEADER_BLOCK_START/END
/// - Slicer identification line
/// - Estimated time, filament length/volume/weight in header
/// - M83 relative extrusion mode
/// - Two layers with CHANGE_LAYER / Z_HEIGHT annotations
/// - FEATURE annotations (Outer wall, Inner wall, Sparse infill)
/// - G0/G1 moves with X/Y/Z/E/F parameters
/// - Retraction (negative E in relative mode)
/// - G92 E0 reset
fn synthetic_gcode_bambu_style() -> String {
    format!(
        r#"; HEADER_BLOCK_START
; BambuStudio 02.05.00.66
; model printing time: 1m 30s
; total layer number: 2
; total filament length [mm] : 100.00
; total filament volume [cm^3] : 0.24
; total filament weight [g] : 0.30
; filament_density: 1.24
; filament_diameter: 1.75
; HEADER_BLOCK_END

G90
M83
G28
M104 S200
M190 S60
G92 E0

; CHANGE_LAYER
; Z_HEIGHT: 0.2
; LAYER_HEIGHT: 0.2
; layer num/total_layer_count: 1/2
; FEATURE: Outer wall
G1 Z0.2 F600
G1 X10 Y0 E0.5 F1200
G1 X10 Y10 E0.5 F1200
G1 X0 Y10 E0.5 F1200
G1 X0 Y0 E0.5 F1200
; FEATURE: Sparse infill
G1 X2 Y2 E0.3 F1800
G1 X8 Y2 E0.3 F1800
G1 X8 Y8 E0.3 F1800
G1 X2 Y8 E0.3 F1800
G1 E-0.8 F2400
G0 X0 Y0 F9000

; CHANGE_LAYER
; Z_HEIGHT: 0.4
; LAYER_HEIGHT: 0.2
; layer num/total_layer_count: 2/2
; FEATURE: Outer wall
G1 Z0.4 F600
G1 X10 Y0 E0.5 F1200
G1 X10 Y10 E0.5 F1200
G1 X0 Y10 E0.5 F1200
G1 X0 Y0 E0.5 F1200
; FEATURE: Inner wall
G1 X1 Y1 E0.4 F1500
G1 X9 Y1 E0.4 F1500
G1 X9 Y9 E0.4 F1500
G1 X1 Y9 E0.4 F1500

G1 E-0.8 F2400
M84
"#
    )
}

