/// Generate a Slicecore-style G-code with `; TYPE:` format matching gcode_gen.rs output.
fn synthetic_gcode_slicecore_style() -> String {
    format!(
        r#"; Generated by slicecore v0.1.0
; Marlin dialect

G90
M83
G28
M104 S200
M190 S60
G92 E0

; TYPE:Outer perimeter
G1 Z0.2 F600
G1 X10 Y0 E0.5 F1200
G1 X10 Y10 E0.5 F1200
G1 X0 Y10 E0.5 F1200
G1 X0 Y0 E0.5 F1200

G1 E-0.8 F2400
M84
"#
    )
}

// =============================================================================
// SC-1: G-code parser extracts layer boundaries, move counts, travel/extrusion
//       distances, and total filament per layer
// =============================================================================

#[test]
fn sc1_layer_boundaries_and_metrics() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Layer count: the parser may detect additional layers from both annotation-based
    // CHANGE_LAYER markers and Z-height changes in G1 moves, so we check >= 2
    assert!(
        analysis.layers.len() >= 2,
        "Should detect at least 2 layers, got {}",
        analysis.layers.len()
    );

    // Find layers at expected Z heights
    let z02_layer = analysis.layers.iter().find(|l| (l.z_height - 0.2).abs() < 0.01);
    let z04_layer = analysis.layers.iter().find(|l| (l.z_height - 0.4).abs() < 0.01);
    assert!(z02_layer.is_some(), "Should have a layer at Z=0.2");
    assert!(z04_layer.is_some(), "Should have a layer at Z=0.4");

    // Move counts > 0 for layers with content
    let z02 = z02_layer.unwrap();
    let z04 = z04_layer.unwrap();
    assert!(z02.move_count > 0, "Layer at Z=0.2 should have moves");
    assert!(z04.move_count > 0, "Layer at Z=0.4 should have moves");

    // Extrusion distance > 0 for layers with content
    assert!(
        z02.extrusion_distance_mm > 0.0,
        "Layer at Z=0.2 should have extrusion distance"
    );
    assert!(
        z04.extrusion_distance_mm > 0.0,
        "Layer at Z=0.4 should have extrusion distance"
    );

    // Total moves > 0
    assert!(analysis.total_moves > 0, "Should have total moves");

    // Total filament > 0
    assert!(
        analysis.total_filament_mm > 0.0,
        "Should have total filament"
    );
}

#[test]
fn sc1_per_layer_travel_distance() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Total travel should be > 0 (we have G0 moves)
    assert!(
        analysis.total_travel_mm > 0.0,
        "Should have travel distance from G0 moves"
    );

    // Total extrusion should be > 0
    assert!(
        analysis.total_extrusion_mm > 0.0,
        "Should have extrusion distance"
    );
}

// =============================================================================
// SC-2: Feature type annotations parsed and per-feature metrics accumulated
// =============================================================================

#[test]
fn sc2_feature_annotations_bambu() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // BambuStudio uses "Outer wall", "Sparse infill", "Inner wall"
    assert!(
        analysis.features.contains_key("Outer wall"),
        "Should have Outer wall feature, got: {:?}",
        analysis.features.keys().collect::<Vec<_>>()
    );
    assert!(
        analysis.features.contains_key("Sparse infill"),
        "Should have Sparse infill feature"
    );
    assert!(
        analysis.features.contains_key("Inner wall"),
        "Should have Inner wall feature"
    );

    // Each feature should have non-zero metrics
    let outer = analysis.features.get("Outer wall").unwrap();
    assert!(
        outer.extrusion_e_mm > 0.0,
        "Outer wall should have extrusion"
    );
    assert!(outer.move_count > 0, "Outer wall should have moves");
}

