// =============================================================================
// SC-3: Retraction count/distance, z-hop count/distance, and speed distribution
// =============================================================================

#[test]
fn sc3_retraction_and_speed_stats() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Retraction count (we have 2 retractions in synthetic gcode)
    assert!(
        analysis.retraction_count >= 2,
        "Should detect retractions (negative E), got: {}",
        analysis.retraction_count
    );
    assert!(
        analysis.retraction_distance_mm > 0.0,
        "Retraction distance should be positive"
    );

    // Speed statistics should have data
    let outer = analysis.features.get("Outer wall").unwrap();
    assert!(
        outer.speed_stats.min_mm_s > 0.0,
        "Should have speed data, min={}",
        outer.speed_stats.min_mm_s
    );
    assert!(
        outer.speed_stats.max_mm_s >= outer.speed_stats.min_mm_s,
        "Max >= min: max={} min={}",
        outer.speed_stats.max_mm_s,
        outer.speed_stats.min_mm_s
    );
    assert!(
        outer.speed_stats.mean_mm_s > 0.0,
        "Mean speed should be positive"
    );
}

#[test]
fn sc3_speed_distribution_multiple_features() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Different features should potentially have different speeds
    let outer = analysis.features.get("Outer wall").unwrap();
    let infill = analysis.features.get("Sparse infill").unwrap();

    // Outer wall at F1200 = 20mm/s, Sparse infill at F1800 = 30mm/s
    assert!(
        (outer.speed_stats.mean_mm_s - 20.0).abs() < 1.0,
        "Outer wall speed should be ~20mm/s, got {}",
        outer.speed_stats.mean_mm_s
    );
    assert!(
        (infill.speed_stats.mean_mm_s - 30.0).abs() < 1.0,
        "Sparse infill speed should be ~30mm/s, got {}",
        infill.speed_stats.mean_mm_s
    );
}

