// =============================================================================
// SC-5: CLI analyze-gcode subcommand (verified by build success in Plan 02,
//       here test JSON output serialization)
// =============================================================================

#[test]
fn sc5_analysis_json_serializable() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Verify JSON serialization works
    let json = serde_json::to_string_pretty(&analysis).unwrap();
    assert!(
        json.contains("Outer wall"),
        "JSON should contain feature names"
    );
    assert!(
        json.contains("BambuStudio"),
        "JSON should contain slicer type"
    );

    // Verify deserialization round-trip
    let deserialized: slicecore_engine::GcodeAnalysis = serde_json::from_str(&json).unwrap();
    assert_eq!(deserialized.filename, "test.gcode");
    assert_eq!(deserialized.slicer, slicecore_engine::SlicerType::BambuStudio);
    assert_eq!(deserialized.layers.len(), analysis.layers.len());
    assert!(
        (deserialized.total_filament_mm - analysis.total_filament_mm).abs() < 0.001,
        "Round-trip filament should match"
    );
}

// =============================================================================
// SC-6: compare-gcode with delta computation
// =============================================================================

#[test]
fn sc6_comparison_deltas() {
    let gcode1 = synthetic_gcode_bambu_style();
    let gcode2 = synthetic_gcode_prusaslicer_style();

    let reader1 = std::io::BufReader::new(gcode1.as_bytes());
    let analysis1 = slicecore_engine::parse_gcode_file(reader1, "bambu.gcode", 1.75, 1.24);

    let reader2 = std::io::BufReader::new(gcode2.as_bytes());
    let analysis2 = slicecore_engine::parse_gcode_file(reader2, "prusa.gcode", 1.75, 1.24);

    let result = slicecore_engine::compare_gcode_analyses(analysis1, vec![analysis2]);

    assert_eq!(
        result.deltas.len(),
        1,
        "Should have one delta (for non-baseline file)"
    );
    assert_eq!(result.deltas[0].filename, "prusa.gcode");

    // Delta fields should be computed (can be positive or negative)
    // Just verify the fields exist and are finite
    assert!(
        result.deltas[0].total_time_delta_s.is_finite(),
        "Time delta should be finite"
    );
    assert!(
        result.deltas[0].filament_delta_mm.is_finite(),
        "Filament delta should be finite"
    );
    // layer_count_delta is i64 so always finite
    let _ = result.deltas[0].layer_count_delta;

    // Comparison JSON serializable
    let json = serde_json::to_string_pretty(&result).unwrap();
    assert!(json.contains("deltas"), "JSON should contain deltas key");
    assert!(
        json.contains("prusa.gcode"),
        "JSON should contain compared filename"
    );
}

#[test]
fn sc6_comparison_same_file() {
    let gcode = synthetic_gcode_bambu_style();

    let reader1 = std::io::BufReader::new(gcode.as_bytes());
    let analysis1 = slicecore_engine::parse_gcode_file(reader1, "file1.gcode", 1.75, 1.24);

    let reader2 = std::io::BufReader::new(gcode.as_bytes());
    let analysis2 = slicecore_engine::parse_gcode_file(reader2, "file2.gcode", 1.75, 1.24);

    let result = slicecore_engine::compare_gcode_analyses(analysis1, vec![analysis2]);

    // Comparing same content should yield zero deltas
    assert!(
        result.deltas[0].total_time_delta_s.abs() < 0.01,
        "Same content should have ~0 time delta"
    );
    assert!(
        result.deltas[0].filament_delta_mm.abs() < 0.01,
        "Same content should have ~0 filament delta"
    );
    assert_eq!(result.deltas[0].layer_count_delta, 0);
}

// =============================================================================
// SC-7: Real BambuStudio G-code validation (gated with #[ignore] for CI)
// =============================================================================

#[test]
#[ignore] // Requires real G-code files in tmp/gcode-bambu/
fn sc7_real_bambustudio_gcode() {
    let path = std::path::Path::new("tmp/gcode-bambu/Cube_PLA.gcode");
    if !path.exists() {
        eprintln!("Skipping: real G-code file not found at {:?}", path);
        return;
    }

    let file = std::fs::File::open(path).unwrap();
    let reader = std::io::BufReader::new(file);
    let analysis = slicecore_engine::parse_gcode_file(reader, "Cube_PLA.gcode", 1.75, 1.24);

    // Should detect BambuStudio
    assert_eq!(analysis.slicer, slicecore_engine::SlicerType::BambuStudio);

    // Should have layers
    assert!(
        analysis.layers.len() > 10,
        "Real cube should have >10 layers, got {}",
        analysis.layers.len()
    );

    // Should have header metadata
    assert!(
        analysis.header.estimated_time_s.is_some(),
        "Should extract time estimate from header"
    );
    assert!(
        analysis.header.filament_length_mm.is_some(),
        "Should extract filament from header"
    );

    // Computed filament should be within reasonable range of header-reported value
    if let Some(header_filament) = analysis.header.filament_length_mm {
        let ratio = analysis.total_filament_mm / header_filament;
        assert!(
            ratio > 0.5 && ratio < 2.0,
            "Computed filament ({:.1}mm) should be within 50-200% of header ({:.1}mm), ratio: {:.2}",
            analysis.total_filament_mm,
            header_filament,
            ratio
        );
    }

    // Should have features
    assert!(
        !analysis.features.is_empty(),
        "Should detect feature annotations"
    );

    // Should have retractions
    assert!(
        analysis.retraction_count > 0,
        "Real print should have retractions"
    );

    println!("Real BambuStudio analysis:");
    println!("  Layers: {}", analysis.layers.len());
    println!(
        "  Total time (computed): {:.1}s",
        analysis.total_time_estimate_s
    );
    println!(
        "  Total time (header): {:?}",
        analysis.header.estimated_time_s
    );
    println!(
        "  Filament (computed): {:.1}mm",
        analysis.total_filament_mm
    );
    println!(
        "  Filament (header): {:?}",
        analysis.header.filament_length_mm
    );
    println!(
        "  Features: {:?}",
        analysis.features.keys().collect::<Vec<_>>()
    );
    println!("  Retractions: {}", analysis.retraction_count);
}

#[test]
#[ignore] // Requires real G-code files in tmp/gcode-bambu/
fn sc7_real_comparison_two_files() {
    let path1 = std::path::Path::new("tmp/gcode-bambu/Cube_PLA.gcode");
    let path2 = std::path::Path::new("tmp/gcode-bambu/3DBenchy_PLA.gcode");
    if !path1.exists() || !path2.exists() {
        eprintln!("Skipping: real G-code files not found");
        return;
    }

    let analysis1 = slicecore_engine::parse_gcode_file(
        std::io::BufReader::new(std::fs::File::open(path1).unwrap()),
        "Cube_PLA.gcode",
        1.75,
        1.24,
    );
    let analysis2 = slicecore_engine::parse_gcode_file(
        std::io::BufReader::new(std::fs::File::open(path2).unwrap()),
        "3DBenchy_PLA.gcode",
        1.75,
        1.24,
    );

    let result = slicecore_engine::compare_gcode_analyses(analysis1, vec![analysis2]);

    // Benchy should have more layers, more filament, more time than a cube
    assert!(
        result.deltas[0].layer_count_delta > 0,
        "Benchy should have more layers than cube"
    );
    assert!(
        result.deltas[0].filament_delta_mm > 0.0,
        "Benchy should use more filament"
    );

    println!("Comparison: Cube vs Benchy");
    println!("  Layer delta: {}", result.deltas[0].layer_count_delta);
    println!(
        "  Filament delta: {:.1}mm",
        result.deltas[0].filament_delta_mm
    );
    println!(
        "  Time delta: {:.1}s",
        result.deltas[0].total_time_delta_s
    );
}

