#[test]
fn edge_case_empty_gcode() {
    let gcode = "";
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "empty.gcode", 1.75, 1.24);
    assert_eq!(analysis.layers.len(), 0);
    assert_eq!(analysis.total_moves, 0);
    assert_eq!(analysis.total_filament_mm, 0.0);
    assert_eq!(analysis.slicer, slicecore_engine::SlicerType::Unknown);
}

#[test]
fn edge_case_comments_only() {
    let gcode = "; This is a comment\n; Another comment\n";
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "comments.gcode", 1.75, 1.24);
    assert_eq!(analysis.layers.len(), 0);
    assert_eq!(analysis.total_moves, 0);
    assert_eq!(analysis.slicer, slicecore_engine::SlicerType::Unknown);
}

#[test]
fn edge_case_m82_absolute_extrusion() {
    // Test absolute extrusion mode tracking
    let gcode =
        "G90\nM82\nG1 Z0.2 F600\nG1 X10 Y0 E1.0 F1200\nG1 X20 Y0 E2.0 F1200\nG92 E0\nG1 X30 Y0 E1.0 F1200\n";
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "m82.gcode", 1.75, 1.24);

    // Total filament should be ~3mm (1.0 + 1.0 + 1.0 after G92 reset)
    assert!(
        (analysis.total_filament_mm - 3.0).abs() < 0.1,
        "M82 absolute extrusion: expected ~3.0mm, got {:.2}mm",
        analysis.total_filament_mm
    );
}

#[test]
fn edge_case_slicecore_gcode_detection() {
    let gcode =
        "; Generated by slicecore v0.1.0\nG90\nM83\nG1 Z0.2 F600\n; TYPE:Outer perimeter\nG1 X10 Y0 E0.5 F1200\n";
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "slicecore.gcode", 1.75, 1.24);
    assert_eq!(analysis.slicer, slicecore_engine::SlicerType::Slicecore);
}

#[test]
fn edge_case_g92_reset_in_absolute_mode() {
    // Verify G92 E0 reset properly resets the E-axis reference point in absolute mode
    let gcode = "M82\nG1 X10 Y0 E5.0 F3000\nG92 E0\nG1 X20 Y0 E3.0 F3000\n";
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "reset.gcode", 1.75, 1.24);

    // First move: E 0->5.0 = 5.0mm, G92 E0 resets, second move: E 0->3.0 = 3.0mm
    // Total = 8.0mm
    assert!(
        (analysis.total_filament_mm - 8.0).abs() < 0.1,
        "G92 E0 reset: expected ~8.0mm, got {:.2}mm",
        analysis.total_filament_mm
    );
}

#[test]
fn edge_case_filament_volume_and_weight() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Volume and weight should be computed from filament length
    assert!(
        analysis.total_filament_volume_mm3 > 0.0,
        "Should have filament volume"
    );
    assert!(
        analysis.total_filament_weight_g > 0.0,
        "Should have filament weight"
    );

    // Cross-check with standalone functions
    let expected_volume =
        slicecore_engine::filament_mm_to_volume_mm3(analysis.total_filament_mm, 1.75);
    let expected_weight =
        slicecore_engine::filament_mm_to_weight_g(analysis.total_filament_mm, 1.75, 1.24);
    assert!(
        (analysis.total_filament_volume_mm3 - expected_volume).abs() < 0.01,
        "Volume should match standalone function"
    );
    assert!(
        (analysis.total_filament_weight_g - expected_weight).abs() < 0.001,
        "Weight should match standalone function"
    );
}

#[test]
fn edge_case_multiple_slicer_comparison() {
    // Compare BambuStudio, PrusaSlicer, and Slicecore outputs
    let gcode1 = synthetic_gcode_bambu_style();
    let gcode2 = synthetic_gcode_prusaslicer_style();
    let gcode3 = synthetic_gcode_slicecore_style();

    let a1 = slicecore_engine::parse_gcode_file(
        std::io::BufReader::new(gcode1.as_bytes()),
        "bambu.gcode",
        1.75,
        1.24,
    );
    let a2 = slicecore_engine::parse_gcode_file(
        std::io::BufReader::new(gcode2.as_bytes()),
        "prusa.gcode",
        1.75,
        1.24,
    );
    let a3 = slicecore_engine::parse_gcode_file(
        std::io::BufReader::new(gcode3.as_bytes()),
        "slicecore.gcode",
        1.75,
        1.24,
    );

    let result = slicecore_engine::compare_gcode_analyses(a1, vec![a2, a3]);

    assert_eq!(
        result.deltas.len(),
        2,
        "Should have 2 deltas (prusa + slicecore)"
    );
    assert_eq!(result.deltas[0].filename, "prusa.gcode");
    assert_eq!(result.deltas[1].filename, "slicecore.gcode");

    // All deltas should have finite values
    for delta in &result.deltas {
        assert!(delta.total_time_delta_s.is_finite());
        assert!(delta.filament_delta_mm.is_finite());
    }
}

#[test]
fn edge_case_time_estimate_consistency() {
    let gcode = synthetic_gcode_bambu_style();
    let reader = std::io::BufReader::new(gcode.as_bytes());
    let analysis = slicecore_engine::parse_gcode_file(reader, "test.gcode", 1.75, 1.24);

    // Total computed time should be the sum of per-layer times
    let layer_time_sum: f64 = analysis
        .layers
        .iter()
        .map(|l| l.layer_time_estimate_s)
        .sum();
    assert!(
        (analysis.total_time_estimate_s - layer_time_sum).abs() < 0.01,
        "Total time ({:.3}s) should equal sum of layer times ({:.3}s)",
        analysis.total_time_estimate_s,
        layer_time_sum
    );
}

